<?php use App\Helpers\Csrf; use App\Helpers\Sanitizer; use App\Helpers\Url; $esEdicion=is_array($parte); ?>
<main class="container"><section class="module-hero"><div><span class="eyebrow">Catálogo</span><h1><?= $esEdicion?'Editar parte':'Nueva parte' ?></h1><p>Define los tipos de piezas que luego estarán disponibles en inventario.</p></div><a class="btn btn-secundario" href="<?= Sanitizer::html(Url::ruta('/partes')) ?>">Volver</a></section><?php if(!empty($errores)): ?><div class="alerta alerta--error"><ul><?php foreach($errores as $error): ?><li><?= Sanitizer::html($error) ?></li><?php endforeach; ?></ul></div><?php endif; ?><form class="card form-wide" method="POST" action="<?= Sanitizer::html(Url::ruta($esEdicion?'/partes/actualizar/'.$parte['id_parte']:'/partes/guardar')) ?>"><?= Csrf::campo() ?><div class="form-group"><label>Nombre</label><input name="nombre_parte" required value="<?= Sanitizer::html($parte['nombre_parte'] ?? '') ?>"></div><div class="form-group"><label>Descripción</label><textarea name="descripcion" rows="3"><?= Sanitizer::html($parte['descripcion'] ?? '') ?></textarea></div><label class="check-line"><input type="checkbox" name="activo" value="1" <?= (int)($parte['activo'] ?? 1)===1?'checked':'' ?>> Activo</label><div class="form-actions"><a class="btn btn-secundario" href="<?= Sanitizer::html(Url::ruta('/partes')) ?>">Cancelar</a><button class="btn">Guardar</button></div></form></main>
